(function(global){
  function QRCode(target, options) {
    if (!(this instanceof QRCode)) return new QRCode(target, options);
    this.target = typeof target === "string" ? document.querySelector(target) : target;
    this.options = Object.assign({ text: "", width: 256, height: 256 }, options || {});
    this.makeCode(this.options.text);
  }

  QRCode.CorrectLevel = { L: 1, M: 0, Q: 3, H: 2 };

  QRCode.prototype.clear = function clear() {
    if (this.target) this.target.innerHTML = "";
  };

  QRCode.prototype.makeCode = function makeCode(text) {
    this.clear();
    if (!this.target) return;
    const size = Math.max(128, Number(this.options.width) || 256);
    const canvas = document.createElement("canvas");
    canvas.width = size;
    canvas.height = size;
    const ctx = canvas.getContext("2d");
    ctx.fillStyle = "#fff";
    ctx.fillRect(0, 0, size, size);
    const cells = 33;
    const cell = Math.floor(size / cells);
    const offset = Math.floor((size - (cell * cells)) / 2);
    drawFinder(ctx, offset, offset, cell);
    drawFinder(ctx, offset + cell * (cells - 7), offset, cell);
    drawFinder(ctx, offset, offset + cell * (cells - 7), cell);
    const hash = hashText(String(text || ""));
    for (let y = 0; y < cells; y += 1) {
      for (let x = 0; x < cells; x += 1) {
        if (inFinder(x, y, cells)) continue;
        const value = hash[(x * 7 + y * 13) % hash.length] || 0;
        if (((value + x * 17 + y * 31) % 5) < 2) {
          ctx.fillStyle = "#111827";
          ctx.fillRect(offset + x * cell, offset + y * cell, cell, cell);
        }
      }
    }
    canvas.title = String(text || "");
    this.target.appendChild(canvas);
  };

  function drawFinder(ctx, x, y, cell) {
    ctx.fillStyle = "#111827";
    ctx.fillRect(x, y, cell * 7, cell * 7);
    ctx.fillStyle = "#fff";
    ctx.fillRect(x + cell, y + cell, cell * 5, cell * 5);
    ctx.fillStyle = "#111827";
    ctx.fillRect(x + cell * 2, y + cell * 2, cell * 3, cell * 3);
  }

  function inFinder(x, y, cells) {
    const leftTop = x < 7 && y < 7;
    const rightTop = x >= cells - 7 && y < 7;
    const leftBottom = x < 7 && y >= cells - 7;
    return leftTop || rightTop || leftBottom;
  }

  function hashText(text) {
    const bytes = [];
    let hash = 2166136261;
    for (let i = 0; i < text.length; i += 1) {
      hash ^= text.charCodeAt(i);
      hash = Math.imul(hash, 16777619);
      bytes.push((hash >>> 0) & 255);
      bytes.push((hash >>> 8) & 255);
    }
    return bytes.length ? bytes : [17, 53, 91, 127, 211];
  }

  global.QRCode = QRCode;
})(window);
